const items = $input.all();
const body = items[0].json.body.body;
if (!Array.isArray(body)) {
  throw new Error("Input must be a JSON array in the request body");
}
const sanitized = body.map(data => {
  let url = data.Link_Matricula_PDF || "";
  url = url.replace(/,/g, '.');
  return {
    ...data,
    Link_Matricula_PDF: url,
    URL_origem: url,
    status_processamento: "pendente",
    data_hora: new Date().toISOString(),
    observacoes: ""
  };
});
// Para teste de amostra, vamos pegar os 15 primeiros itens (pode mudar para processar tudo)
const sliced = sanitized.slice(0, 50);
return [{
  json: {
    items: sliced,
    index: 0,
    results: [],
    continue: sliced.length > 0
  }
}];

const input = $input.first().json;
const currentItem = input.items[input.index];
return [{
  json: {
    ...currentItem,
    _state: {
      items: input.items,
      index: input.index,
      results: input.results
    }
  }
}];

const currentItem = $('Set Current Item').item.json;
const state = currentItem._state;
const processedItem = {
  ...currentItem,
  status_processamento: "revisao_manual",
  observacoes: "Link quebrado ou erro HTTP ao baixar o PDF"
};
delete processedItem._state;
const nextIndex = state.index + 1;
return [{
  json: {
    items: state.items,
    index: nextIndex,
    results: [...state.results, processedItem],
    continue: nextIndex < state.items.length
  }
}];

