const text = $input.first().json.text;
const cleanText = text.replace(/\s+/g, ' ').substring(0, 15000);
const prompt = `Analise o texto de matrícula de imóvel abaixo e extraia as informações fiscais e de propriedade estritamente conforme as regras:

REGRAS CRÍTICAS:
1. Extraia apenas dados LITERALMENTE presentes no texto. Não invente nenhum dado (sem alucinações).
2. Se uma informação não estiver explícita na matrícula, preencha o campo correspondente como "não encontrado".
3. Identifique se o imóvel sofreu execução por inadimplência (leilão extrajudicial, consolidação da propriedade por alienação fiduciária, adjudicação, arrematação). Se sim, extraia o(s) proprietário(s) anterior(es) afetado(s) e o número da averbação.

TEXTO DA MATRÍCULA:
---START---
${cleanText}
---END---

Retorne a resposta estritamente no seguinte formato JSON. Não adicione nenhuma explicação extra ou Markdown:
{
  "numero_matricula_cartorio": "número da matrícula e o cartório / ofício de registro de imóveis",
  "inscricao_municipal": "inscrição municipal/imobiliária do imóvel",
  "contribuinte": "contribuinte (titular vinculado)",
  "proprietarios_atuais": ["nome do proprietário 1", "nome do proprietário 2"],
  "indicador_execucao_inadimplencia": true ou false,
  "proprietarios_anteriores": ["nome do proprietário anterior 1"] ou [],
  "averbacao_execucao": "número ou descrição da averbação de consolidação/leilão" ou "não encontrado",
  "data_ultima_compra_venda": "data no formato DD/MM/AAAA",
  "valor_ultima_compra_venda": "valor em R$",
  "valor_avaliacao": "valor de avaliação em R$",
  "onus_gravames": "lista de ônus ativos (hipoteca, penhora, etc.) ou 'não encontrado'"
}`;
return [{ json: { prompt } }];

const currentItem = $('Set Current Item').item.json;
const state = currentItem._state;

let result = {};
try {
  const aiOutput = $('AI Extraction').item.json.output;
  let parsed = aiOutput;
  if (typeof parsed === 'string') {
    const jsonMatch = parsed.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      parsed = JSON.parse(jsonMatch[0]);
    } else {
      parsed = JSON.parse(parsed);
    }
  }
  result = {
    ...currentItem,
    ...parsed,
    status_processamento: "sucesso",
    observacoes: ""
  };
} catch (e) {
  result = {
    ...currentItem,
    status_processamento: "revisao_manual",
    observacoes: "Erro ao analisar resposta da IA: " + e.message
  };
}

delete result._state;

const nextIndex = state.index + 1;
return [{
  json: {
    items: state.items,
    index: nextIndex,
    results: [...state.results, result],
    continue: nextIndex < state.items.length
  }
}];
